def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity < 0:
            priorities[i] = np.inf
            continue
        if capacity == 0:
            priorities[i] = np.inf if item > 0 else 0
            continue
        ratio = item / capacity
        if ratio == 0:
            priorities[i] = 0
            continue
        if ratio > 2:
            priorities[i] = np.inf
            continue
        if 1 < ratio <= 2:
            penalty = 0
            for k in range(1, 6):
                factor = (-1) ** k * (ratio ** (2 * k + 1)) / (k * 3)
                penalty += factor
            base = (ratio ** 4) / 2
            priorities[i] = base + abs(penalty)
        elif 0 < ratio <= 1:
            score = 0
            sign = 1
            for j in range(1, 8):
                term = sign * (ratio ** j) / (j + (j % 3))
                score += term
                if j % 2 == 0:
                    sign *= -1
            multiplier = 20 if ratio < 0.25 else 12 if ratio < 0.5 else 7 if ratio < 0.75 else 3
            priorities[i] = abs(score) * multiplier
            if ratio > 0.7:
                extra = 0
                for m in range(1, 5):
                    extra += ((-1) ** m) * (ratio ** (m + 1)) / (m + 2)
                priorities[i] += abs(extra) * 2
        else:
            if item == 0:
                priorities[i] = 0
                continue
            else:
                pri = 0
                for x in range(1, 4):
                    for y in range(1, 4):
                        pri += ((-1) ** (x + y)) * (item ** x) / (capacity ** y) / (x + y)
                priorities[i] = abs(pri)
    mean_prior = np.mean(priorities[np.isfinite(priorities)])
    for i in range(len(priorities)):
        if np.isinf(priorities[i]):
            priorities[i] = mean_prior * 10
        elif priorities[i] == 0 and item != 0:
            priorities[i] = mean_prior * 0.5
    return priorities
